DROP TABLE IF EXISTS inventaire_batons;
CREATE TABLE IF NOT EXISTS `inventaire_batons` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `nom` VARCHAR(255) NOT NULL,
  `essence_bois` VARCHAR(100) DEFAULT NULL,
  `forme_embout` VARCHAR(100) DEFAULT NULL,
  `type_pointe` VARCHAR(100) DEFAULT NULL,
  `type_cristal` VARCHAR(100) DEFAULT NULL,
  `longueur_cm` DECIMAL(5,2) DEFAULT NULL,
  `courbure` VARCHAR(50) DEFAULT NULL,
  `accessoires` TEXT DEFAULT NULL,
  `age_annees` INT DEFAULT NULL,
  `prix_po` DECIMAL(10,2) DEFAULT NULL,
  `emplacement_entrepot` VARCHAR(100) DEFAULT NULL,
  `element_alignement` VARCHAR(50) DEFAULT NULL,
  `bonus_magique` INT DEFAULT NULL,
  `pays_origine` VARCHAR(100) DEFAULT NULL,
  `date_ajout` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
SET AUTOCOMMIT = 0;
START TRANSACTION;


COMMIT;